`, test.msg, test.key, test.rounds)
			continue
		}

		if string(decrypted) != test.expected {
			failed++
			t.Errorf(`---------------------------------
Inputs:      msg: %v, key: %v, rounds: %d
Expecting:   decrypted: %s
Actual:      decrypted: %s
